const express = require('express');
const multer = require('multer');
const path = require('path');
const crypto = require('crypto');
const fs = require('fs').promises;
const fileType = require('file-type');

const app = express();

const UPLOAD_DIR = path.join(__dirname, 'uploads');
const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB
const MAX_FILES = 5;

const ALLOWED_MIME_TYPES = {
  'image/jpeg': ['.jpg', '.jpeg'],
  'image/png': ['.png'],
  'image/gif': ['.gif'],
  'application/pdf': ['.pdf'],
  'text/plain': ['.txt']
};

const MAGIC_NUMBERS = {
  'image/jpeg': ['ffd8ff'],
  'image/png': ['89504e47'],
  'image/gif': ['474946383761', '474946383961'],
  'application/pdf': ['25504446'],
  'text/plain': []
};

async function ensureUploadDir() {
  try {
    await fs.access(UPLOAD_DIR);
  } catch {
    await fs.mkdir(UPLOAD_DIR, { recursive: true, mode: 0o755 });
  }
}

async function validateFileContent(filePath, mimeType) {
  const buffer = await fs.readFile(filePath);
  
  if (buffer.length === 0) {
    throw new Error('Empty file not allowed');
  }

  const detectedType = await fileType.fromBuffer(buffer);
  
  if (mimeType === 'text/plain') {
    const textContent = buffer.toString('utf8', 0, Math.min(buffer.length, 1024));
    if (/[\x00-\x08\x0B\x0C\x0E-\x1F]/.test(textContent)) {
      throw new Error('Invalid text file content');
    }
    return true;
  }

  if (!detectedType || detectedType.mime !== mimeType) {
    throw new Error('File content does not match declared type');
  }

  const magicNumbers = MAGIC_NUMBERS[mimeType];
  if (magicNumbers && magicNumbers.length > 0) {
    const fileHeader = buffer.toString('hex', 0, Math.max(...magicNumbers.map(m => m.length / 2)));
    const isValid = magicNumbers.some(magic => fileHeader.startsWith(magic));
    if (!isValid) {
      throw new Error('Invalid file signature');
    }
  }

  return true;
}

function sanitizeFilename(filename) {
  const ext = path.extname(filename).toLowerCase();
  const nameWithoutExt = path.basename(filename, ext);
  const sanitized = nameWithoutExt.replace(/[^a-zA-Z0-9_-]/g, '_').substring(0, 50);
  return sanitized || 'file';
}

const storage = multer.diskStorage({
  destination: async (req, file, cb) => {
    await ensureUploadDir();
    cb(null, UPLOAD_DIR);
  },
  filename: (req, file, cb) => {
    const randomName = crypto.randomBytes(16).toString('hex');
    const sanitizedName = sanitizeFilename(file.originalname);
    const ext = path.extname(file.originalname).toLowerCase();
    cb(null, `${randomName}_${sanitizedName}${ext}`);
  }
});

const fileFilter = (req, file, cb) => {
  const mimeType = file.mimetype.toLowerCase();
  
  if (!ALLOWED_MIME_TYPES[mimeType]) {
    return cb(new Error('File type not allowed'), false);
  }

  const ext = path.extname(file.originalname).toLowerCase();
  const allowedExtensions = ALLOWED_MIME_TYPES[mimeType];
  
  if (!allowedExtensions.includes(ext)) {
    return cb(new Error('File extension does not match MIME type'), false);
  }

  if (file.originalname.includes('..') || file.originalname.includes('/') || file.originalname.includes('\\')) {
    return cb(new Error('Invalid filename'), false);
  }

  cb(null, true);
};

const upload = multer({
  storage: storage,
  fileFilter: fileFilter,
  limits: {
    fileSize: MAX_FILE_SIZE,
    files: MAX_FILES,
    fields: 10,
    fieldSize: 1024
  }
});

async function handleFileUpload(req, res) {
  try {
    if (!req.files || req.files.length === 0) {
      return res.status(400).json({ error: 'No files uploaded' });
    }

    const validatedFiles = [];
    const errors = [];

    for (const file of req.files) {
      try {
        const filePath = file.path;
        const mimeType = file.mimetype.toLowerCase();

        await validateFileContent(filePath, mimeType);

        await fs.chmod(filePath, 0o644);

        validatedFiles.push({
          filename: file.filename,
          originalName: sanitizeFilename(file.originalname),
          size: file.size,
          mimeType: file.mimetype,
          uploadDate: new Date().toISOString()
        });
      } catch (error) {
        errors.push({
          filename: file.originalname,
          error: error.message
        });
        
        try {
          await fs.unlink(file.path);
        } catch (unlinkError) {
          console.error('Failed to delete invalid file:', unlinkError);
        }
      }
    }

    if (validatedFiles.length === 0) {
      return res.status(400).json({ 
        error: 'No valid files uploaded',
        details: errors
      });
    }

    res.status(200).json({
      message: 'Files uploaded successfully',
      files: validatedFiles,
      errors: errors.length > 0 ? errors : undefined
    });

  } catch (error) {
    console.error('Upload error:', error);
    
    if (req.files) {
      for (const file of req.files) {
        try {
          await fs.unlink(file.path);
        } catch (unlinkError) {
          console.error('Failed to delete file:', unlinkError);
        }
      }
    }

    res.status(500).json({ error: 'File upload failed' });
  }
}

app.post('/upload', upload.array('files', MAX_FILES), handleFileUpload);

app.use((error, req, res, next) => {
  if (error instanceof multer.MulterError) {
    if (error.code === 'LIMIT_FILE_SIZE') {
      return res.status(400).json({ error: `File too large. Maximum size is ${MAX_FILE_SIZE} bytes` });
    }
    if (error.code === 'LIMIT_FILE_COUNT') {
      return res.status(400).json({ error: `Too many files. Maximum is ${MAX_FILES}` });
    }
    return res.status(400).json({ error: error.message });
  }
  
  if (error) {
    return res.status(400).json({ error: error.message });
  }
  
  next();
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = { handleFileUpload, app };